import React, { useState, useEffect, useCallback, useMemo } from "react";

const LOGO = "data:image/png;base64,";
const RED = "#B5222A", RED_DK = "#7E1419", GOLD = "#E6CF2D", GOLD_SOFT = "#C9A227";
const INK = "#141210", INK2 = "#1E1A17", INK3 = "#272019", CREAM = "#F4ECD8", MUT = "#9a9183";
const WARN = "#d98b2b", OK = "#5fa86a", BLUE = "#5b8bb0", PURP = "#9b7fb0";

const POLES = [
  { id: "gestion", nom: "Gestion", referent: "Anne Roncaglia", couleur: RED },
  { id: "secretariat", nom: "Secrétariat", referent: "Véronique Ferrand", couleur: "#C0562A" },
  { id: "developpement", nom: "Développement", referent: "Steaven Thomas", couleur: GOLD_SOFT },
  { id: "communication", nom: "Communication", referent: "À nommer", couleur: "#9C2B2F" },
  { id: "sportif", nom: "Sportif", referent: "Cyril Court", couleur: "#A83328" },
  { id: "benevoles", nom: "Bénévoles", referent: "Franck Reinert", couleur: "#B8472B" },
];
const MEMBRES = ["Frédéric Fouque", "Cyril Court", "Franck Reinert", "Anne Roncaglia", "Véronique Ferrand", "Sophie Agnelli", "Marie Rouman", "Steaven Thomas"];

// fréquences possibles
const FREQS = ["Hebdomadaire", "Mensuel", "Saisonnier", "Annuel"];

// Socle officiel : [intitulé, fréquence] — fréquences issues du fichier GESTION_VHB_2026
const SOCLE = {
  gestion: [
    ["Transmettre les éléments de paie à l'expert-comptable", "Mensuel"],
    ["Suivi et paiement des cotisations (CDOS)", "Mensuel"],
    ["Suivi des chèques et opérations bancaires", "Hebdomadaire"],
    ["Calcul des frais bénévoles (déplacements)", "Mensuel"],
    ["Préparer le budget prévisionnel N+1", "Annuel"],
  ],
  secretariat: [
    ["Relevé du courrier et des boîtes mail", "Hebdomadaire"],
    ["Enregistrement des licences", "Hebdomadaire"],
    ["Implantation des matchs, réservation gymnase", "Hebdomadaire"],
    ["Rédaction des comptes-rendus de CA", "Après réunion"],
    ["Import / export Gesthand", "Hebdomadaire"],
    ["Classement des dossiers licences", "Mensuel"],
  ],
  developpement: [
    ["Dossiers de subvention (ANS, Métropole, Ville)", "À date"],
    ["Recherche et suivi des sponsors", "À date"],
    ["Partenariats équipements (maillots, ballons)", "Avant saison"],
    ["Loto, calendrier, Challenge Alain Guerrier", "Annuel"],
    ["Gestion de la buvette (stocks, planning)", "Chaque week-end"],
  ],
  communication: [
    ["Définir une stratégie de com simple", "Annuel"],
    ["Publier résultats et photos des matchs", "Hebdomadaire"],
    ["Annoncer les événements du club", "À date"],
    ["Tenir le site internet à jour", "Mensuel"],
  ],
  sportif: [
    ["Suivi des entraîneurs et des équipes", "Hebdomadaire"],
    ["Gestion des matchs du week-end", "Hebdomadaire"],
    ["Gestion des stages", "Saisonnier"],
    ["Recrutement joueurs et coachs", "Saisonnier"],
    ["Suivi des jeunes coachs", "Mensuel"],
  ],
  benevoles: [
    ["Recenser les besoins par créneau", "Saisonnier"],
    ["Recruter et accueillir les bénévoles", "Continu"],
    ["Tenir le planning de bénévolat", "Hebdomadaire"],
    ["Organiser un moment convivial", "Annuel"],
  ],
};

const FIELDS = [
  { key: "avance", label: "Ce qui a avancé", hint: "Réalisé depuis le dernier CA", color: OK },
  { key: "bloque", label: "Ce qui est bloqué", hint: "Ce qui n'avance pas, et pourquoi", color: WARN },
  { key: "besoin", label: "Ce dont j'ai besoin du CA", hint: "Une décision, un budget, de l'aide", color: RED },
];
const STATUTS = { todo: { label: "À faire", color: MUT }, doing: { label: "En cours", color: BLUE }, done: { label: "Fait", color: OK } };
const RECUR = { todo: { label: "À faire", color: WARN }, ajour: { label: "À jour", color: OK } };

const STORE_KEY = "vhb_ca_v4";
const uid = () => Math.random().toString(36).slice(2, 9);
const emptyPole = () => ({ avance: "", bloque: "", besoin: "", odj: [], extra: [] });
const blankState = () => { const o = {}; POLES.forEach(p => o[p.id] = emptyPole()); return o; };

function dayDiff(d) { if (!d) return null; const x = new Date(d + "T00:00:00"); const n = new Date(); n.setHours(0,0,0,0); return Math.round((x - n)/86400000); }
function echLabel(due) { const dd = dayDiff(due); if (dd === null) return null; if (dd < 0) return { t: `Retard ${-dd}j`, c: RED }; if (dd === 0) return { t: "Aujourd'hui", c: WARN }; if (dd <= 7) return { t: `Dans ${dd}j`, c: WARN }; return { t: `Dans ${dd}j`, c: MUT }; }

function useShared() {
  const [data, setData] = useState(null); const [saving, setSaving] = useState(false);
  useEffect(() => { (async () => { try { const r = await window.storage.get(STORE_KEY, true); setData(r && r.value ? JSON.parse(r.value) : blankState()); } catch { setData(blankState()); } })(); }, []);
  const persist = useCallback(async (next) => { setData(next); setSaving(true); try { await window.storage.set(STORE_KEY, JSON.stringify(next), true); } catch {} setTimeout(() => setSaving(false), 250); }, []);
  return { data, persist, saving };
}
function useMe() {
  const [me, setMe] = useState(null);
  useEffect(() => { (async () => { try { const r = await window.storage.get("vhb_me", false); if (r && r.value) setMe(r.value); } catch {} })(); }, []);
  const choose = async (n) => { setMe(n); try { await window.storage.set("vhb_me", n, false); } catch {} };
  return { me, choose };
}

export default function App() {
  const { data, persist, saving } = useShared();
  const { me, choose } = useMe();
  const [view, setView] = useState("accueil");
  const [openPole, setOpenPole] = useState(null);
  if (!data) return <Splash />;
  if (!me) return <Login onChoose={choose} />;

  const update = (pid, patch) => persist({ ...data, [pid]: { ...data[pid], ...patch } });
  const patchExtra = (pid, id, patch) => update(pid, { extra: data[pid].extra.map(t => t.id === id ? { ...t, ...patch } : t) });

  return (
    <div style={{ minHeight: "100vh", background: INK, color: CREAM, fontFamily: "'Inter',system-ui,sans-serif" }}>
      <style>{CSS}</style>
      <header style={hdr}>
        <img src={LOGO} width={40} height={40} alt="VHB" style={{ cursor: "pointer" }} onClick={() => { setView("accueil"); setOpenPole(null); }} />
        <div style={{ lineHeight: 1.05 }}>
          <div className="cond" style={{ fontSize: 15 }}>VHB · Pilotage du CA</div>
          <div className="cond" style={{ fontSize: 10, color: GOLD_SOFT, letterSpacing: ".12em" }}>Outil d'équipe</div>
        </div>
        <div style={{ marginLeft: "auto", display: "flex", gap: 8, alignItems: "center" }}>
          <span style={{ fontSize: 10.5, color: saving ? GOLD : MUT }} className="cond">{saving ? "Sync…" : "Partagé"}</span>
          <div className="seg">
            {[["accueil","Accueil"],["taches","Tâches"],["prep","Préparation"],["reunion","Réunion"]].map(([v,l]) => (
              <button key={v} className={"segb cond " + (view===v?"on":"")} onClick={() => { setView(v); setOpenPole(null); }}>{l}</button>
            ))}
          </div>
          <button className="me cond" onClick={() => choose(null)} title="Changer de profil">{me.split(" ")[0]}</button>
        </div>
      </header>

      {view === "accueil" && <Accueil data={data} me={me} patchExtra={patchExtra} goTaches={() => setView("taches")} />}
      {view === "taches" && <Taches data={data} me={me} update={update} patchExtra={patchExtra} />}
      {view === "prep" && !openPole && <Prep data={data} onOpen={setOpenPole} onGo={() => setView("reunion")} />}
      {view === "prep" && openPole && <PoleEditor pole={openPole} d={data[openPole.id]} onChange={(p) => update(openPole.id, p)} onBack={() => setOpenPole(null)} />}
      {view === "reunion" && <Reunion data={data} onToggle={(pid, i) => update(pid, { odj: data[pid].odj.map((o, idx) => idx===i ? {...o, traite: !o.traite} : o) })} onBack={() => setView("prep")} />}

      <footer style={{ textAlign: "center", padding: "24px 16px", color: "#6b635a", fontSize: 11, borderTop: "1px solid rgba(230,207,45,.12)", marginTop: 28 }}>
        <span className="cond" style={{ color: GOLD_SOFT }}>1975 — 2025 · 50 ans</span> · Vitrolles Handball Jeunes
      </footer>
    </div>
  );
}

function Splash() { return <div style={{ minHeight: "100vh", background: INK, color: GOLD_SOFT, display: "flex", alignItems: "center", justifyContent: "center" }}><style>{CSS}</style><span className="cond">Chargement…</span></div>; }
function Login({ onChoose }) {
  return (<div style={{ minHeight: "100vh", background: INK, color: CREAM, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}><style>{CSS}</style>
    <div className="fade" style={{ textAlign: "center", maxWidth: 420 }}>
      <img src={LOGO} width={110} height={110} alt="VHB" />
      <h1 className="display" style={{ fontSize: 30, margin: "16px 0 6px" }}>Qui es-tu ?</h1>
      <p style={{ color: MUT, fontSize: 14, marginBottom: 22 }}>Choisis ton nom pour qu'on sache qui fait quoi. Pas de mot de passe.</p>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>{MEMBRES.map(m => <button key={m} className="loginb cond" onClick={() => onChoose(m)}>{m}</button>)}</div>
    </div></div>);
}

/* ---------- ACCUEIL ---------- */
function Accueil({ data, me, patchExtra, goTaches }) {
  const all = useMemo(() => { const a = []; POLES.forEach(p => (data[p.id].extra || []).forEach(t => a.push({ ...t, pole: p }))); return a; }, [data]);
  const aide = all.filter(t => t.aide && !isDone(t));
  const enCours = all.filter(t => t.type === "ponctuel" ? t.statut === "doing" : t.recur === "todo");
  const ponctuels = all.filter(t => t.type === "ponctuel");
  const doneCount = ponctuels.filter(t => t.statut === "done").length;

  return (
    <main style={wrap} className="fade">
      <h1 className="display" style={{ fontSize: "clamp(24px,5vw,38px)", margin: 0 }}>Salut <span style={{ color: RED }}>{me.split(" ")[0]}</span> 👋</h1>
      <p style={{ color: MUT, marginTop: 8, fontSize: 14.5, maxWidth: 560, lineHeight: 1.55 }}>Voici où en est le club aujourd'hui. Si quelqu'un a besoin d'un coup de main, c'est ici qu'on le voit — et qu'on peut aider.</p>
      <div style={{ display: "flex", gap: 26, marginTop: 18 }}>
        <Mini big={enCours.length} label="en cours / à faire" />
        <Mini big={aide.length} label="appels à l'aide" accent={aide.length > 0} />
        <Mini big={ponctuels.length ? `${Math.round(doneCount/ponctuels.length*100)}%` : "—"} label="objectifs terminés" />
      </div>

      <section style={{ marginTop: 26 }}>
        <div className="cond" style={{ fontSize: 13, color: aide.length ? RED : MUT, marginBottom: 10 }}>{aide.length ? "🙋 On a besoin d'aide ici" : "Personne ne demande d'aide en ce moment"}</div>
        {aide.length === 0 && <div style={{ background: INK2, borderRadius: 12, padding: 18, color: MUT, fontSize: 13.5 }}>Quand quelqu'un marque une tâche « besoin d'aide », elle apparaît ici pour que tout le monde puisse se porter volontaire.</div>}
        {aide.map(t => (
          <div key={t.id} className="helpcard">
            <span style={{ width: 11, height: 11, borderRadius: 3, background: t.pole.couleur, flexShrink: 0 }} />
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 14.5 }}>{t.txt}</div>
              <div className="cond" style={{ fontSize: 11, color: MUT, marginTop: 2 }}>{t.pole.nom}{t.assignee ? ` · ${t.assignee.split(" ")[0]}` : ""}{t.type === "recurrent" ? ` · ${t.freq}` : (t.due ? ` · ${echLabel(t.due)?.t || ""}` : "")}</div>
            </div>
            {t.helpers && t.helpers.includes(me) ? <span className="cond tagok">Tu aides ✓</span>
              : <button className="btn-gold cond" style={{ padding: "7px 14px", fontSize: 12 }} onClick={() => patchExtra(t.pole.id, t.id, { helpers: [...(t.helpers||[]), me] })}>Je viens aider</button>}
          </div>
        ))}
      </section>

      <section style={{ marginTop: 28 }}>
        <div className="cond" style={{ fontSize: 13, color: BLUE, marginBottom: 10 }}>⏳ Ce qui demande de l'attention maintenant</div>
        {enCours.length === 0 && <div style={{ background: INK2, borderRadius: 12, padding: 18, color: MUT, fontSize: 13.5 }}>Rien en cours. Les tâches récurrentes « à faire » et les ponctuelles « en cours » apparaîtront ici.</div>}
        {enCours.map(t => (
          <div key={t.id} className="inprow">
            <span style={{ width: 11, height: 11, borderRadius: 3, background: t.pole.couleur, flexShrink: 0 }} />
            <span style={{ flex: 1, fontSize: 14 }}>{t.txt}</span>
            <span className="cond" style={{ fontSize: 10, color: t.type === "recurrent" ? PURP : BLUE }}>{t.type === "recurrent" ? t.freq : "Ponctuel"}</span>
            <span className="cond" style={{ fontSize: 11, color: MUT }}>{t.assignee ? t.assignee.split(" ")[0] : t.pole.nom}</span>
          </div>
        ))}
      </section>

      <div style={{ marginTop: 24, textAlign: "center" }}><button className="btn-gold cond" onClick={goTaches}>Voir toutes les tâches →</button></div>
    </main>
  );
}
function isDone(t) { return t.type === "ponctuel" ? t.statut === "done" : t.recur === "ajour"; }
function Mini({ big, label, accent }) { return <div><div className="display" style={{ fontSize: 30, color: accent ? GOLD : CREAM, lineHeight: 1 }}>{big}</div><div className="cond" style={{ fontSize: 10.5, color: MUT, marginTop: 3 }}>{label}</div></div>; }

/* ---------- TÂCHES ---------- */
function Taches({ data, me, update, patchExtra }) {
  return (
    <main style={wrap} className="fade">
      <h1 className="display" style={{ fontSize: "clamp(22px,5vw,34px)", margin: 0 }}>Les <span style={{ color: RED }}>tâches</span> du club.</h1>
      <p style={{ color: MUT, marginTop: 8, fontSize: 14, maxWidth: 640, lineHeight: 1.55 }}>
        Deux familles : les <b style={{ color: PURP }}>récurrentes</b> (le travail de fond qui revient) et les <b style={{ color: BLUE }}>ponctuelles</b> (un objectif avec une échéance). Le socle 🔒 affiche sa fréquence d'origine.
      </p>
      {POLES.map(p => <PoleTasks key={p.id} pole={p} d={data[p.id]} me={me} onChange={patch => update(p.id, patch)} patchExtra={(id, patch) => patchExtra(p.id, id, patch)} />)}
    </main>
  );
}

function PoleTasks({ pole, d, me, onChange, patchExtra }) {
  const [adding, setAdding] = useState(false);
  const [txt, setTxt] = useState(""); const [type, setType] = useState("recurrent");
  const [freq, setFreq] = useState("Mensuel"); const [due, setDue] = useState("");
  const extras = d.extra || [];
  const recurrents = extras.filter(t => t.type === "recurrent");
  const ponctuels = extras.filter(t => t.type === "ponctuel");

  const add = () => {
    const v = txt.trim(); if (!v) return;
    const base = { id: uid(), txt: v, type, assignee: "", aide: false, helpers: [] };
    const t = type === "recurrent" ? { ...base, freq, recur: "todo" } : { ...base, due: due || "", statut: "todo" };
    onChange({ extra: [...extras, t] }); setTxt(""); setDue(""); setAdding(false);
  };
  const del = (id) => onChange({ extra: extras.filter(t => t.id !== id) });

  return (
    <section style={{ marginTop: 24 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, borderBottom: `2px solid ${pole.couleur}`, paddingBottom: 8 }}>
        <span style={{ width: 13, height: 13, borderRadius: 4, background: pole.couleur }} />
        <h2 className="cond" style={{ margin: 0, fontSize: 18 }}>{pole.nom}</h2>
        <span className="cond" style={{ marginLeft: "auto", fontSize: 11, color: MUT }}>{pole.referent}</span>
      </div>

      {/* SECTION RÉCURRENTES */}
      <div className="cond" style={{ fontSize: 11, color: PURP, margin: "14px 0 7px", letterSpacing: ".1em" }}>↻ Récurrentes · le travail de fond</div>
      {SOCLE[pole.id].map(([t, f], i) => (
        <div key={"s"+i} className="srow">
          <span title="Socle, non supprimable" style={{ fontSize: 12, opacity: .55 }}>🔒</span>
          <span style={{ flex: 1, fontSize: 13.5, color: "#cfc6b6" }}>{t}</span>
          <span className="freqtag cond" style={{ color: PURP, borderColor: "rgba(155,127,176,.4)" }}>{f}</span>
          <span className="cond" style={{ fontSize: 10, color: MUT, minWidth: 38, textAlign: "right" }}>Socle</span>
        </div>
      ))}
      {recurrents.map(t => {
        const st = RECUR[t.recur || "todo"];
        return (
          <div key={t.id} className="erow">
            <button className="statusb cond" onClick={() => patchExtra(t.id, { recur: t.recur === "todo" ? "ajour" : "todo" })} style={{ color: st.color, borderColor: st.color }}>{st.label}</button>
            <span style={{ flex: 1, minWidth: 120, fontSize: 14 }}>{t.txt}</span>
            <span className="freqtag cond" style={{ color: PURP, borderColor: "rgba(155,127,176,.4)" }}>{t.freq}</span>
            <select className="sel cond" value={t.assignee || ""} onChange={e => patchExtra(t.id, { assignee: e.target.value })}>
              <option value="">Personne</option>{MEMBRES.map(m => <option key={m} value={m}>{m.split(" ")[0]}</option>)}
            </select>
            <button className={"helpb cond " + (t.aide ? "on" : "")} onClick={() => patchExtra(t.id, { aide: !t.aide })}>{t.aide ? "Aide demandée" : "Besoin d'aide"}</button>
            <button className="x" onClick={() => del(t.id)}>×</button>
          </div>
        );
      })}

      {/* SECTION PONCTUELLES */}
      <div className="cond" style={{ fontSize: 11, color: BLUE, margin: "16px 0 7px", letterSpacing: ".1em" }}>◷ Ponctuelles · avec une échéance</div>
      {ponctuels.length === 0 && <div style={{ fontSize: 12.5, color: MUT, padding: "2px 11px 6px" }}>Aucune pour l'instant.</div>}
      {ponctuels.map(t => {
        const st = STATUTS[t.statut || "todo"]; const ech = echLabel(t.due);
        return (
          <div key={t.id} className="erow">
            <button className="statusb cond" onClick={() => patchExtra(t.id, { statut: t.statut === "todo" ? "doing" : t.statut === "doing" ? "done" : "todo" })} style={{ color: st.color, borderColor: st.color }}>{st.label}</button>
            <span style={{ flex: 1, minWidth: 120, fontSize: 14, color: t.statut === "done" ? MUT : CREAM, textDecoration: t.statut === "done" ? "line-through" : "none" }}>{t.txt}</span>
            <input type="date" value={t.due || ""} onChange={e => patchExtra(t.id, { due: e.target.value })} className="dateinp" />
            {ech && <span className="cond" style={{ fontSize: 10, color: ech.c, minWidth: 60, textAlign: "right" }}>{ech.t}</span>}
            <select className="sel cond" value={t.assignee || ""} onChange={e => patchExtra(t.id, { assignee: e.target.value })}>
              <option value="">Personne</option>{MEMBRES.map(m => <option key={m} value={m}>{m.split(" ")[0]}</option>)}
            </select>
            <button className={"helpb cond " + (t.aide ? "on" : "")} onClick={() => patchExtra(t.id, { aide: !t.aide })}>{t.aide ? "Aide demandée" : "Besoin d'aide"}</button>
            <button className="x" onClick={() => del(t.id)}>×</button>
          </div>
        );
      })}

      {/* AJOUT */}
      {adding ? (
        <div className="addbox" style={{ flexDirection: "column", alignItems: "stretch", gap: 10 }}>
          <input autoFocus value={txt} onChange={e => setTxt(e.target.value)} onKeyDown={e => e.key === "Enter" && add()} placeholder="Intitulé de la tâche…" className="inp" />
          <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
            <div className="typetog">
              <button className={"typeb cond " + (type === "recurrent" ? "on" : "")} onClick={() => setType("recurrent")} style={type==="recurrent"?{background:PURP}:{}}>↻ Récurrente</button>
              <button className={"typeb cond " + (type === "ponctuel" ? "on" : "")} onClick={() => setType("ponctuel")} style={type==="ponctuel"?{background:BLUE}:{}}>◷ Ponctuelle</button>
            </div>
            {type === "recurrent"
              ? <select className="sel cond" value={freq} onChange={e => setFreq(e.target.value)}>{FREQS.map(f => <option key={f} value={f}>{f}</option>)}</select>
              : <input type="date" value={due} onChange={e => setDue(e.target.value)} className="dateinp" />}
            <button className="btn-gold cond" style={{ padding: "0 16px", marginLeft: "auto" }} onClick={add}>Ajouter</button>
            <button className="link cond" onClick={() => { setAdding(false); setTxt(""); setDue(""); }}>Annuler</button>
          </div>
        </div>
      ) : <button className="addbtn cond" onClick={() => setAdding(true)}>+ Ajouter une tâche</button>}
    </section>
  );
}

/* ---------- PRÉPARATION ---------- */
function Prep({ data, onOpen, onGo }) {
  const prepd = POLES.filter(p => { const d = data[p.id]; return d.avance || d.bloque || d.besoin || d.odj.length; }).length;
  const pts = POLES.reduce((s, p) => s + data[p.id].odj.length, 0);
  return (
    <main style={wrap} className="fade">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 14 }}>
        <div><h1 className="display" style={{ fontSize: "clamp(24px,5vw,38px)", margin: 0 }}>On prépare le <span style={{ color: RED }}>prochain CA.</span></h1>
          <p style={{ color: MUT, marginTop: 8, fontSize: 14.5, maxWidth: 520, lineHeight: 1.55 }}>Chacun remplit son pôle. Le jour du CA, l'onglet Réunion assemble tout.</p></div>
        <div style={{ display: "flex", gap: 22 }}><Mini big={`${prepd}/${POLES.length}`} label="pôles préparés" /><Mini big={pts} label="points" accent /></div>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(280px,1fr))", gap: 14, marginTop: 26 }}>
        {POLES.map(p => { const d = data[p.id]; const prep = d.avance || d.bloque || d.besoin || d.odj.length;
          return (<div key={p.id} className="card" onClick={() => onOpen(p)} style={{ borderColor: prep ? p.couleur : "rgba(255,255,255,.08)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 11 }}><span style={{ width: 12, height: 12, borderRadius: 4, background: p.couleur }} /><h3 className="cond" style={{ margin: 0, fontSize: 17 }}>{p.nom}</h3><span style={{ marginLeft: "auto", fontSize: 11, color: prep ? GOLD : MUT }} className="cond">{prep ? "Préparé" : "À remplir"}</span></div>
            <div className="cond" style={{ fontSize: 11, color: MUT, marginTop: 7 }}>{p.referent}</div>
            <div style={{ display: "flex", gap: 6, marginTop: 14 }}>{FIELDS.map(f => <span key={f.key} style={{ flex: 1, height: 5, borderRadius: 6, background: d[f.key] ? f.color : "rgba(255,255,255,.09)" }} />)}</div>
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 12, fontSize: 12, color: MUT }}><span>{d.odj.length} point{d.odj.length>1?"s":""}</span><span style={{ color: GOLD_SOFT }} className="cond">Ouvrir →</span></div>
          </div>); })}
      </div>
      <div style={{ marginTop: 24, textAlign: "center" }}><button className="btn-gold cond" onClick={onGo}>Passer en Vue réunion →</button></div>
    </main>
  );
}
function PoleEditor({ pole, d, onChange, onBack }) {
  const [np, setNp] = useState("");
  const add = () => { const v = np.trim(); if (!v) return; onChange({ odj: [...d.odj, { txt: v, traite: false }] }); setNp(""); };
  return (<main style={{ ...wrap, maxWidth: 760 }} className="fade">
    <button className="link cond" onClick={onBack}>← Tous les pôles</button>
    <div style={{ display: "flex", alignItems: "center", gap: 12, margin: "14px 0 4px" }}><span style={{ width: 16, height: 16, borderRadius: 5, background: pole.couleur }} /><h1 className="display" style={{ fontSize: 30, margin: 0 }}>{pole.nom}</h1></div>
    <div className="cond" style={{ color: MUT, fontSize: 12, marginBottom: 22 }}>Référent · {pole.referent}</div>
    {FIELDS.map(f => (<div key={f.key} style={{ marginBottom: 18 }}>
      <label className="cond" style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13, marginBottom: 7 }}><span style={{ width: 9, height: 9, borderRadius: 3, background: f.color }} />{f.label}<span style={{ color: MUT, textTransform: "none", letterSpacing: 0, fontWeight: 400, fontSize: 11.5 }}>· {f.hint}</span></label>
      <textarea value={d[f.key]} onChange={e => onChange({ [f.key]: e.target.value })} placeholder="Écris ici…" className="ta" rows={2} /></div>))}
    <label className="cond" style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13, marginBottom: 9 }}><span style={{ width: 9, height: 9, borderRadius: 3, background: GOLD }} />Points à l'ordre du jour</label>
    {d.odj.map((o, i) => (<div key={i} className="odjrow"><span style={{ color: GOLD_SOFT, fontSize: 13 }}>{i+1}.</span><span style={{ flex: 1, fontSize: 14 }}>{o.txt}</span><button className="x" onClick={() => onChange({ odj: d.odj.filter((_, idx) => idx !== i) })}>×</button></div>))}
    <div style={{ display: "flex", gap: 8, marginTop: 8 }}><input value={np} onChange={e => setNp(e.target.value)} onKeyDown={e => e.key === "Enter" && add()} placeholder="Ajouter un point…" className="inp" /><button className="btn-gold cond" style={{ padding: "0 18px" }} onClick={add}>Ajouter</button></div>
    <div style={{ marginTop: 26, textAlign: "center" }}><button className="link cond" onClick={onBack}>✓ Enregistré · revenir</button></div>
  </main>);
}
function Reunion({ data, onToggle, onBack }) {
  const today = new Date().toLocaleDateString("fr-FR", { day: "numeric", month: "long", year: "numeric" });
  const active = POLES.filter(p => { const d = data[p.id]; return d.avance || d.bloque || d.besoin || d.odj.length; });
  return (<main style={{ ...wrap, maxWidth: 820 }} className="fade">
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10 }}>
      <div><div className="cond" style={{ color: GOLD_SOFT, fontSize: 12 }}>Ordre du jour · CA du {today}</div><h1 className="display" style={{ fontSize: "clamp(24px,5vw,36px)", margin: "4px 0 0" }}>La réunion, déjà prête.</h1></div>
      <button className="link cond" onClick={onBack}>← Préparation</button></div>
    {active.length === 0 && <div style={{ marginTop: 30, padding: 26, background: INK2, borderRadius: 14, color: MUT, textAlign: "center" }}>Aucun pôle préparé pour l'instant.</div>}
    {active.map((p, idx) => { const d = data[p.id]; return (<section key={p.id} style={{ marginTop: 22 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, borderBottom: `2px solid ${p.couleur}`, paddingBottom: 8 }}><span className="display" style={{ color: p.couleur, fontSize: 18 }}>{String(idx+1).padStart(2,"0")}</span><h2 className="cond" style={{ margin: 0, fontSize: 19 }}>{p.nom}</h2><span className="cond" style={{ marginLeft: "auto", fontSize: 11, color: MUT }}>{p.referent}</span></div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 12, marginTop: 12 }}>{FIELDS.map(f => d[f.key] ? (<div key={f.key} style={{ background: INK2, borderRadius: 10, padding: "11px 13px", borderLeft: `3px solid ${f.color}` }}><div className="cond" style={{ fontSize: 10.5, color: f.color, marginBottom: 4 }}>{f.label}</div><div style={{ fontSize: 13.5, lineHeight: 1.5, whiteSpace: "pre-wrap" }}>{d[f.key]}</div></div>) : null)}</div>
      {d.odj.length > 0 && (<div style={{ marginTop: 12 }}><div className="cond" style={{ fontSize: 11, color: GOLD_SOFT, marginBottom: 6 }}>À débattre · coche en séance</div>
        {d.odj.map((o, i) => (<div key={i} className="meetrow" onClick={() => onToggle(p.id, i)}><span style={{ width: 19, height: 19, borderRadius: 5, flexShrink: 0, border: o.traite ? "none" : "1.5px solid #5c554b", background: o.traite ? p.couleur : "transparent", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, color: "#fff" }}>{o.traite ? "✓" : ""}</span><span style={{ fontSize: 14, color: o.traite ? MUT : CREAM, textDecoration: o.traite ? "line-through" : "none" }}>{o.txt}</span></div>))}</div>)}
    </section>); })}
  </main>);
}

